		gMapGrid[kMapGridWidth][kMapGridHeight];PicturePtr			gMapCurrMapPict			= NULL;SpritePtr			gMapCurrMapOverlay		= NULL;PicturePtr			gMapCurrBattlePict		= NULL;Rect				gMapSrcRect				= {0, 0, 0, 0};Rect				gMapDstRect				= {0, 0, 0, 0};ATSUStyle				gstyle;ATSUAttributeTag		gtags[2]	= {kATSUQDBoldfaceTag, kATSUColorTag};ByteCount				gbytes[2]	= {sizeof(Boolean), sizeof(RGBColor)};Boolean					gisBold		= true;RGBColor				gtextColor	= {65535, 65535, 65535};ATSUAttributeValuePtr	gptrs[2]	= {&gisBold, &gtextColor};TXNTextBoxOptionsData	goptions;//*************************************************************************************//  internal function declerations//*************************************************************************************pascal OSStatus	MapMenuEventHandler		(EventHandlerCallRef	myHandler,										EventRef				event,										void *					userData);pascal OSStatus	MapAppEventHandler		(EventHandlerCallRef	myHandler,										EventRef				event,										void *					userData);pascal OSStatus MapKeyEventHandler		(EventHandlerCallRef	myHandler,										EventRef				event,										void *					userData);pascal OSStatus MapMouseEventHandler	(EventHandlerCallRef	myHandler,										EventRef				event,										void *					userData);pascal OSStatus MapWindowEventHandler	(EventHandlerCallRef	myHandler,										EventRef				event,										void *					userData);//*************************************************************************************//  Map Mode functions//*************************************************************************************void InstallMapMode (WindowRef myWindow){	error = GetPicture(kMapScreenUI, &gMapScreenUI);	ErrorCheck(error, "\pDAMapMode:InstallMapMode:GetPicture");	error = GetSprite(kMapScreenUIOverlay1, &gMapScreenUIOverlay1);	ErrorCheck(error, "\pDAMapMode:InstallMapMode:GetSprite");	error = GetSprite(kMapScreenUIOverlay2, &gMapScreenUIOverlay2);	ErrorCheck(error, "\pDAMapMode:InstallMapMode:GetSprite");	ATSUCreateStyle(&gstyle);	ATSUSetAttributes(gstyle, 2, gtags, gbytes, gptrs);	goptions.optionTags = kTXNSetFlushnessMask;	goptions.flushness = kATSUCenterAlignment;	goptions.justification = kATSUFullJustification;	goptions.rotation = 0;	goptions.options = NULL;}void InstallMapModeHandlers (WindowRef myWindow){	EventTypeSpec	menuSpec		= {kEventClassCommand,		kEventCommandProcess};	EventTypeSpec	appSpec			= {kEventClassApplication,	kEventAppActivated};	EventTypeSpec	keySpec[2]	= 	{{kEventClassKeyboard,		kEventRawKeyDown},									{kEventClassKeyboard,		kEventRawKeyRepeat}};	EventTypeSpec	mouseSpec[3]	= {{kEventClassMouse,		kEventMouseDown},									{kEventClassMouse,			kEventMouseDragged},									{kEventClassMouse,			kEventMouseMoved}};	EventTypeSpec	windowSpec		= {kEventClassWindow,		kEventWindowDrawContent};	error = InstallApplicationEventHandler(NewEventHandlerUPP(MapMenuEventHandler), 1, &menuSpec, myWindow, &gMapMenuHandlerRef);	ErrorCheck(error, "\pDAMapMode:InstallMapModeHandlers:InstallApplicationEventHandler");	error = InstallApplicationEventHandler(NewEventHandlerUPP(MapAppEventHandler), 1, &appSpec, myWindow, &gMapAppHandlerRef);	ErrorCheck(error, "\pDAMapMode:InstallMapModeHandlers:InstallApplicationEventHandler");	error = InstallWindowEventHandler(myWindow, NewEventHandlerUPP(MapKeyEventHandler), 2, keySpec, myWindow, &gMapKeyHandlerRef);	ErrorCheck(error, "\pDAMapMode:InstallMapModeHandlers:InstallApplicationEventHandler");	error = InstallWindowEventHandler(myWindow, NewEventHandlerUPP(MapMouseEventHandler), 3, mouseSpec, myWindow, &gMapMouseHandlerRef);	ErrorCheck(error, "\pDAMapMode:InstallMapModeHandlers:InstallApplicationEventHandler");	error = InstallWindowEventHandler(myWindow, NewEventHandlerUPP(MapWindowEventHandler), 1, &windowSpec, myWindow, &gMapWindowHandlerRef);	ErrorCheck(error, "\pDAMapMode:InstallMapModeHandlers:InstallApplicationEventHandler");}void UninstallMapModeHandlers (void){	RemoveEventHandler(gMapMenuHandlerRef);	RemoveEventHandler(gMapAppHandlerRef);	RemoveEventHandler(gMapKeyHandlerRef);	RemoveEventHandler(gMapMouseHandlerRef);	RemoveEventHandler(gMapWindowHandlerRef);}void UninstallMapMode (void){	error = DisposePicture(gMapScreenUI);	ErrorCheck(error, "\pDAMapMode:UninstallMapMode:DisposePicture");	error = DisposeSprite(gMapScreenUIOverlay1);	ErrorCheck(error, "\pDAMapMode:UninstallMapMode:DisposeSprite");	error = DisposeSprite(gMapScreenUIOverlay2);	ErrorCheck(error, "\pDAMapMode:UninstallMapMode:DisposeSprite");	error = DisposeResource((Handle)gMapCurrMap);	ErrorCheck(error, "\pDAMapMode:UninstallMapMode:DisposeResource");	error = DisposePicture(gMapCurrMapPict);	ErrorCheck(error, "\pDAMapMode:UninstallMapMode:DisposePicture");	error = DisposeSprite(gMapCurrMapOverlay);	ErrorCheck(error, "\pDAMapMode:UninstallMapMode:DisposeSprite");	error = DisposePicture(gMapCurrBattlePict);	ErrorCheck(error, "\pDAMapMode:UninstallMapMode:DisposeSprite");	ATSUDisposeStyle(gstyle);}//*************************************************************************************//  Map Event functions//*************************************************************************************void MapMouseAction (Point * mouseLoc){	do	{		if(mouseLoc->h > 127 && mouseLoc->v > 87)		{			mouseLoc->h -= 128;			mouseLoc->v -= 88;			if(mouseLoc->v > 7 * mouseLoc->h / 10 && mouseLoc->v < -8 * mouseLoc->h / 10 + 511)				DrawMapMove(leftKey);			else if(mouseLoc->v > -6 * mouseLoc->h / 10 + 426 && mouseLoc->v < 8 * mouseLoc->h / 10 - 12)				DrawMapMove(rightKey);			else if(mouseLoc->v < 7 * mouseLoc->h / 10 && mouseLoc->v < -6 * mouseLoc->h / 10 + 426)				DrawMapMove(upKey);			else if(mouseLoc->v > -8 * mouseLoc->h / 10 + 511 && mouseLoc->v > 8 * mouseLoc->h / 10 - 12)				DrawMapMove(downKey);		}		GetMouse(mouseLoc);		FlushEvents(everyEvent, 0);		MoviesTask(NULL, DoTheRightThing);	}	while(Button() == true);}void MapKeyAction (short key){	do	{		switch(key)		{			case leftKey:			case pad4Key:				DrawMapMove(leftKey);				break;			case rightKey:			case pad6Key:				DrawMapMove(rightKey);				break;			case downKey:			case pad2Key:				DrawMapMove(downKey);				break;			case upKey:			case pad8Key:				DrawMapMove(upKey);				break;			case returnKey:			case enterKey:				short mapFacing;				switch(GetCharMapFacing())				{					case kMapFacingNorth1:					case kMapFacingNorth2:						mapFacing = upKey;						break;					case kMapFacingWest1:					case kMapFacingWest2:						mapFacing = leftKey;						break;					case kMapFacingSouth1:					case kMapFacingSouth2:						mapFacing = downKey;						break;					case kMapFacingEast1:					case kMapFacingEast2:					default:						mapFacing = rightKey;						break;				}				MapCanMove(GetCharMapPositionX() / 32, GetCharMapPositionY() / 32, mapFacing);				break;			case eKey:				Equipment();				break;			case hKey:				MapHelp();				break;			case mKey:				MagicWindow(false);				break;			case oKey:				OpenGame();				break;			case qKey:				QuitGame();				break;			case sKey:				MapSaveGame();				break;			case tKey:				TechWindow(false);				break;			case escKey:				QuitGame();				break;		}		key = GetKeys();		FlushEvents(everyEvent, 0);		MoviesTask(NULL, DoTheRightThing);	}	while(Key() == true);}//*************************************************************************************//  Map Menu functions//*************************************************************************************void MapSaveGame (void){	SaveCharacter();}void MapSaveGameAs (void){	SaveCharacterAs();}void MapHelp (void){	PicturePtr pict;	error = GetPicture(kMapScreenHelp, &pict);	ErrorCheck(error, "\pDAMapMode:MapHelp:GetPicture");	error = DrawPicture(pict, 128, 88);	ErrorCheck(error, "\pDAMapMode:MapHelp:DrawPicture");	if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)		QDFlushPortBuffer(GetWindowPort(GameWindow()), NULL);	Delay(8, 0);	FlushEvents(everyEvent, 0);	while(!Button() && !Key())	{		FlushEvents(everyEvent, 0);		MoviesTask(NULL, DoTheRightThing);	}	error = DisposePicture(pict);	ErrorCheck(error, "\pDAMapMode:MapHelp:DisposePicture");	DrawMapAll();	FlushEvents(everyEvent, 0);}//*************************************************************************************//  Map Action functions//*************************************************************************************Boolean MapCanMove (short mapX, short mapY, short direction){	if(direction == leftKey)		mapX--;	else if(direction == rightKey)		mapX++;	else if(direction == downKey)		mapY++;	else if(direction == upKey)		mapY--;	if(mapX < 0)	{		if((**gMapCurrMap).westWarp.mapID != 0)			MapWarpAction((**gMapCurrMap).westWarp.plugID, (**gMapCurrMap).westWarp.mapID, (**gMapCurrMap).westWarp.x, (**gMapCurrMap).westWarp.y, false);		return false;	}	else if(mapX >= kMapGridWidth)	{		if((**gMapCurrMap).eastWarp.mapID != 0)			MapWarpAction((**gMapCurrMap).eastWarp.plugID, (**gMapCurrMap).eastWarp.mapID, (**gMapCurrMap).eastWarp.x, (**gMapCurrMap).eastWarp.y, false);		return false;	}	else if(mapY < 0)	{		if((**gMapCurrMap).northWarp.mapID != 0)			MapWarpAction((**gMapCurrMap).northWarp.plugID, (**gMapCurrMap).northWarp.mapID, (**gMapCurrMap).northWarp.x, (**gMapCurrMap).northWarp.y, false);		return false;	}	else if(mapY >= kMapGridHeight)	{		if((**gMapCurrMap).southWarp.mapID != 0)			MapWarpAction((**gMapCurrMap).southWarp.plugID, (**gMapCurrMap).southWarp.mapID, (**gMapCurrMap).southWarp.x, (**gMapCurrMap).southWarp.y, false);		return false;	}	if(gMapGrid[mapX][mapY] == 0)		return true;	if(gMapGrid[mapX][mapY] != -1)		MapObjectAction((**gMapCurrMap).object[gMapGrid[mapX][mapY] - 1]);	return false;}Boolean MapWarpAction (short plugID, short mapID, short x, short y, Boolean update){	if(plugID != GetCharPlugID() || mapID != GetCharMapID() || update == true)		if(LoadMap(plugID, mapID) == false)		{			Str255 plugName;			GetPlugInName(plugID, &plugName);			pstrcat(plugName, "\p needs to be installed to continue.");			NonFatalError(plugName);			return false;		}	if(plugID != GetCharPlugID())	{		Str255 plugPath;		GetPlugInPath(plugID, &plugPath);		pstrcat(plugPath, "\pmap.mid");		error = InstallBMusic(plugPath);		ErrorCheck(error, "\pDAMapMode:MapWarpAction:InstallBMusic");	}	if(x == -1)		x = GetCharMapPositionX() / 32;	if(y == -1)		y = GetCharMapPositionY() / 32;	SetCharMapPosition(plugID, mapID, x * 32, y * 32);	DrawMapAll();	return true;}void MapTalkAction (Str255 myString){	SetGWorld(OldWindow());	AlertStdAlertParamRec alertParam;	alertParam.movable			= true;	alertParam.helpButton		= false;	alertParam.filterProc		= NULL;	alertParam.defaultText		= "\pOK";	alertParam.cancelText		= NULL;	alertParam.otherText		= NULL;	alertParam.defaultButton	= kAlertStdAlertOKButton;	alertParam.cancelButton		= 0;	alertParam.position			= kWindowCenterMainScreen;	SInt16 itemHit;	StandardAlert(kAlertNoteAlert, myString, NULL, &alertParam, &itemHit);	SetPortWindowPort(GameWindow());}Boolean MapYesNoAction (Str255 myString){	SetGWorld(OldWindow());	AlertStdAlertParamRec alertParam;	alertParam.movable			= true;	alertParam.helpButton		= false;	alertParam.filterProc		= NULL;	alertParam.defaultText		= "\pYes";	alertParam.cancelText		= "\pNo";	alertParam.otherText		= NULL;	alertParam.defaultButton	= kAlertStdAlertOKButton;	alertParam.cancelButton		= kAlertStdAlertCancelButton;	alertParam.position			= kWindowCenterMainScreen;	SInt16 itemHit;	StandardAlert(kAlertNoteAlert, myString, NULL, &alertParam, &itemHit);	SetPortWindowPort(GameWindow());	if(itemHit == kAlertStdAlertOKButton)		return true;	return false;}void MapObjectAction (Object object){	Boolean isDrawMap = true;	switch(object.type)	{		case kMapObjectWarp:			MapWarpAction(object.data[0], object.data[1], object.data[2], object.data[3], false);			break;		case kMapObjectReg:			UpdateMap(GetCharPlugID());			break;		case kMapObjectDraw:			break;		case kMapObjectWall:			break;		case kMapObjectTalk:			BeginPlugUseResourceFile(GetCharPlugID());			Text ** text = (Text **)GetResource(kTextResType, object.data[1]);			ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");			MapTalkAction((**text).text);			Object ** newObject = NULL;			if(object.data[3] != 0)			{				newObject = (Object **)GetResource(kObjectResType, object.data[3]);				ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");				DetachResource((Handle)newObject);			}			ReleaseResource((Handle)text);			EndPlugUseResourceFile();			if(object.data[2] != 0)			{				SetCharFlag(object.data[2]);				UpdateMap(GetCharPlugID());			}			if(object.data[3] != 0)			{				MapObjectAction(**newObject);				DisposeHandle((Handle)newObject);			}			break;		case kMapObjectYesNo:			BeginPlugUseResourceFile(GetCharPlugID());			text = (Text **)GetResource(kTextResType, object.data[1]);			ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");			newObject = NULL;			if(MapYesNoAction((**text).text) == true)			{				if(object.data[2] != 0)				{					newObject = (Object **)GetResource(kObjectResType, object.data[2]);					ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");					DetachResource((Handle)newObject);				}			}			else			{				if(object.data[3] != 0)				{					newObject = (Object **)GetResource(kObjectResType, object.data[3]);					ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");					DetachResource((Handle)newObject);				}			}			ReleaseResource((Handle)text);			EndPlugUseResourceFile();			if(newObject != NULL)			{				MapObjectAction(**newObject);				DisposeHandle((Handle)newObject);			}			break;		case kMapObjectGetItem:			ItemRef item = {object.data[1], object.data[2], object.data[3]};			if(RemoveCharItem(item) == true)				if(object.data[0] != 0)				{					SetCharFlag(object.data[0]);					UpdateMap(GetCharPlugID());				}			break;		case kMapObjectHeal:			TotalHeal();			if(object.data[1] != 0)			{				BeginPlugUseResourceFile(GetCharPlugID());				newObject = (Object **)GetResource(kObjectResType, object.data[1]);				ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");				DetachResource((Handle)newObject);				EndPlugUseResourceFile();				MapObjectAction(**newObject);				DisposeHandle((Handle)newObject);			}			break;		case kMapObjectLvUp:			CharLvUp();			if(object.data[1] != 0)			{				BeginPlugUseResourceFile(GetCharPlugID());				newObject = (Object **)GetResource(kObjectResType, object.data[1]);				ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");				DetachResource((Handle)newObject);				EndPlugUseResourceFile();				MapObjectAction(**newObject);				DisposeHandle((Handle)newObject);			}			break;		case kMapObjectShop:			Shop(object.data[1]);			if(object.data[2] != 0)			{				BeginPlugUseResourceFile(GetCharPlugID());				newObject = (Object **)GetResource(kObjectResType, object.data[2]);				ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");				DetachResource((Handle)newObject);				EndPlugUseResourceFile();				MapObjectAction(**newObject);				DisposeHandle((Handle)newObject);			}			break;		case kMapObjectTreasure:			Treasure(object.data[1]);			if(object.data[2] != 0)			{				SetCharFlag(object.data[2]);				UpdateMap(GetCharPlugID());			}			if(object.data[3] != 0)			{				BeginPlugUseResourceFile(GetCharPlugID());				newObject = (Object **)GetResource(kObjectResType, object.data[3]);				ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");				DetachResource((Handle)newObject);				EndPlugUseResourceFile();				MapObjectAction(**newObject);				DisposeHandle((Handle)newObject);			}			break;		case kMapObjectBattle:			if(Battle(object.data[1]) == true)			{				if(object.data[2] != 0)				{					SetCharFlag(object.data[2]);					UpdateMap(GetCharPlugID());				}				if(object.data[3] != 0)				{					BeginPlugUseResourceFile(GetCharPlugID());					newObject = (Object **)GetResource(kObjectResType, object.data[3]);					ErrorCheck(ResError(), "\pDAMapMode:MapObjectAction:GetResource");					DetachResource((Handle)newObject);					EndPlugUseResourceFile();					MapObjectAction(**newObject);					DisposeHandle((Handle)newObject);				}			}			else				isDrawMap = false;			break;	}	if(isDrawMap == true)		DrawMapAll();}void RandomBattle (void){	if(Random(100) <= kMapBattlePerc)		if(Random(kMaxMapRandomBattles * kMapNormalBattleWeight + kMaxMapRareBattles * kMapRareBattleWeight) <= kMaxMapRandomBattles * kMapNormalBattleWeight)		{			Battle((**gMapCurrMap).randomBattle[Random(kMaxMapRandomBattles) - 1]);			return;		}		else		{			Battle((**gMapCurrMap).rareBattle[Random(kMaxMapRareBattles) - 1]);			return;		}}//*************************************************************************************//  Map Graphic functions//*************************************************************************************Boolean LoadMap (short plugID, short mapID){	// Get the path and open it	Str255 path;	GetPlugInPath(plugID, &path);	pstrcat(path, "\pData");	error = BeginUseResourceFile(path);	ErrorCheck(error, "\pDAMapMode:LoadMap:BeginUseResourceFile");	// Return if plug is present or other type of error	if(error != noErr)		return false;	DrawLoad(-1, 300, 512); //**Load**	// Dispose old map data	error = DisposeResource((Handle)gMapCurrMap);	ErrorCheck(error, "\pDAMapMode:LoadMap:DisposeResource");	error = DisposeSprite(gMapCurrMapOverlay);	ErrorCheck(error, "\pDAMapMode:LoadMap:DisposeSprite");	error = DisposePicture(gMapCurrBattlePict);	ErrorCheck(error, "\pDAMapMode:LoadMap:DisposePicture");	// Get the resource	DrawLoad(10, 300, 512); //**Load**	error = GetResource(kMapResType, mapID, (Handle *)&gMapCurrMap);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetResource");	error = EndUseResourceFile();	ErrorCheck(error, "\pDAMapMode:LoadMap:EndUseResourceFile");	// get the grid	DrawLoad(20, 300, 512); //**Load**	MoviesTask(NULL, DoTheRightThing);	path[0] -= 4;	pstrcat(path, (**gMapCurrMap).mapName);	pstrcat(path, "\p.mask");	PicHandle tempPict;	error = GetPurePicture(path, &tempPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetPurePicture");	DrawLoad(30, 300, 512); //**Load**	error = GetPicture(tempPict, &gMapCurrMapOverlay);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetPicture");	error = DisposePicture(tempPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:DisposePicture");	CGrafPtr oldPort;	DrawLoad(40, 300, 512); //**Load**	MoviesTask(NULL, DoTheRightThing);	error = GetGWorld(&oldPort);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetGWorld");	error = SetGWorld(gMapCurrMapOverlay);	ErrorCheck(error, "\pDAMapMode:LoadMap:SetGWorld");	RGBColor pixelColor;	for(short i = 0; i < kMapGridWidth; i++)		for(short j = 0; j < kMapGridHeight; j++)		{			GetCPixel(i * 32 + 16, j * 32 + 16, &pixelColor);			if(pixelColor.red == 0 && pixelColor.green == 0 && pixelColor.blue == 0)				gMapNormalGrid[i][j] = -1;			else				gMapNormalGrid[i][j] = 0;		}	error = SetGWorld(oldPort);	ErrorCheck(error, "\pDAMapMode:LoadMap:SetGWorld");	error = DisposePicture(gMapCurrMapOverlay);	ErrorCheck(error, "\pDAMapMode:LoadMap:DisposePicture");	// get the map and map data	DrawLoad(50, 300, 512); //**Load**	MoviesTask(NULL, DoTheRightThing);	UpdateMap(plugID);	// get the overlay	DrawLoad(60, 300, 512); //**Load**	path[0] -= 5;	pstrcat(path, "\p.map2");	error = GetPurePicture(path, &tempPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetPurePicture");	DrawLoad(70, 300, 512); //**Load**	error = GetSprite(tempPict, &gMapCurrMapOverlay);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetSprite");	error = DisposePicture(tempPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:DisposePicture");	// get the map battle background	DrawLoad(80, 300, 512); //**Load**	MoviesTask(NULL, DoTheRightThing);	path[0] -= 5;	pstrcat(path, "\p.battle");	error = GetPurePicture(path, &tempPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetPurePicture");	DrawLoad(90, 300, 512); //**Load**	error = GetPicture(tempPict, &gMapCurrBattlePict);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetPicture");	error = DisposePicture(tempPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:DisposePicture");	DrawLoad(100, 300, 512); //**Load**	return true;}void UpdateMap (short plugID){	// get base map picture	DisposePicture(gMapCurrMapPict);	Str255 path;	GetPlugInPath(plugID, &path);	pstrcat(path, (**gMapCurrMap).mapName);	pstrcat(path, "\p.map");	PicHandle tempPict;	error = GetPurePicture(path, &tempPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetPurePicture");	error = GetPicture(tempPict, &gMapCurrMapPict);	ErrorCheck(error, "\pDAMapMode:LoadMap:GetPicture");	error = DisposePicture(tempPict);	// restore normal grid	for(short i = 0; i < kMapGridWidth; i++)		for(short j = 0; j < kMapGridHeight; j++)			gMapGrid[i][j] = gMapNormalGrid[i][j];	// calc objects	for(short i = 0; i < kMaxMapObjects  && (**gMapCurrMap).object[i].type != 0; i++)	{		for(short j = (**gMapCurrMap).object[i].mapLoc[0]; j <= (**gMapCurrMap).object[i].mapLoc[2]; j++)			for(short k = (**gMapCurrMap).object[i].mapLoc[1]; k <= (**gMapCurrMap).object[i].mapLoc[3]; k++)				switch((**gMapCurrMap).object[i].type)				{					case kMapObjectWarp:						gMapGrid[j][k] = i + 1;						break;					case kMapObjectReg:						break;					case kMapObjectDraw:						break;					case kMapObjectWall:					case kMapObjectTalk:					case kMapObjectYesNo:					case kMapObjectGetItem:					case kMapObjectHeal:					case kMapObjectLvUp:					case kMapObjectShop:					case kMapObjectTreasure:					case kMapObjectBattle:						if(GetCharFlag((**gMapCurrMap).object[i].data[0]) == false)							gMapGrid[j][k] = i + 1;						break;				}		if((**gMapCurrMap).object[i].type == kMapObjectDraw && GetCharFlag((**gMapCurrMap).object[i].data[0]) == false)		{			BeginPlugUseResourceFile(plugID);			SpritePtr sprite;			error = GetSprite((**gMapCurrMap).object[i].data[1], &sprite);			ErrorCheck(error, "\pDAMapMode:LoadMap:GetSprite");			CGrafPtr oldPort;			GetGWorld(&oldPort);			SetGWorld(gMapCurrMapPict);			error = DrawSprite(sprite, (**gMapCurrMap).object[i].data[2] * 32, (**gMapCurrMap).object[i].data[3] * 32);			ErrorCheck(error, "\pDAMapMode:LoadMap:DrawSprite");			SetGWorld(oldPort);			DisposeSprite(sprite);			EndPlugUseResourceFile();		}	}}void DrawMapUI (void){	error = DrawPicture(gMapScreenUI);	ErrorCheck(error, "\pDAMapMode:DrawMapUI:DrawPicture");}void DrawMap (void){	Point mapPosition = GetCharMapPosition();	SetRect(&gMapSrcRect, -320, -224, 352, 288);	SetRect(&gMapDstRect, 128, 88, 800, 600);	OffsetRect(&gMapSrcRect, mapPosition.h, mapPosition.v);	Boolean needsBlack = false;	if(gMapSrcRect.top < 0)	{		needsBlack = true;		short adjust = 0 - gMapSrcRect.top;		gMapSrcRect.top += adjust;		gMapDstRect.top += adjust;	}	if(gMapSrcRect.left < 0)	{		needsBlack = true;		short adjust = 0 - gMapSrcRect.left;		gMapSrcRect.left += adjust;		gMapDstRect.left += adjust;	}	if(gMapSrcRect.bottom >= kMapGridHeight * 32)	{		needsBlack = true;		short adjust = gMapSrcRect.bottom - kMapGridHeight * 32;		gMapSrcRect.bottom -= adjust;		gMapDstRect.bottom -= adjust;	}	if(gMapSrcRect.right >= kMapGridWidth * 32)	{		needsBlack = true;		short adjust = gMapSrcRect.right - kMapGridWidth * 32;		gMapSrcRect.right -= adjust;		gMapDstRect.right -= adjust;	}	if(needsBlack == true)	{		Rect uiRect = {88, 128, 600, 800};		error = DrawPicture(gMapScreenUI, &uiRect, &uiRect);		ErrorCheck(error, "\pDAMapMode:DrawMap:DrawPicture");	}	error = DrawPicture(gMapCurrMapPict, &gMapSrcRect, &gMapDstRect);	ErrorCheck(error, "\pDAMapMode:DrawMap:DrawPicture");}void DrawMapOverlay (void){	error = DrawSprite(gMapCurrMapOverlay, &gMapSrcRect, &gMapDstRect);	ErrorCheck(error, "\pDAMapMode:DrawMapOverlay:DrawSprite");}void DrawMapUIOverlay (void){	error = DrawSprite(gMapScreenUIOverlay1, 128, 88);	ErrorCheck(error, "\pDAMapMode:DrawMapOverlay:DrawSprite");	error = DrawSprite(gMapScreenUIOverlay2, 160, 88);	ErrorCheck(error, "\pDAMapMode:DrawMapOverlay:DrawSprite");	}void DrawMapName (void){	Rect dstRect = {42, 315, 62, 565};	char ctext[256];	CopyPascalStringToC((**gMapCurrMap).mapName, ctext);	TXNDrawCFStringTextBox(__CFStringMakeConstantString(ctext), &dstRect, gstyle, &goptions);}void DrawMapCharName (void){	Rect dstRect = {140, 18, 155, 119};	char text[256];	GetCharName(text);	TXNDrawCFStringTextBox(__CFStringMakeConstantString(text), &dstRect, gstyle, &goptions);}void DrawMapCharLv (void){	Rect dstRect = {155, 18, 170, 119};	char text[256];	GetCharLv(text);	TXNDrawCFStringTextBox(__CFStringMakeConstantString(text), &dstRect, gstyle, &goptions);}void DrawMapCharHP (void){	Rect dstRect = {170, 18, 185, 119};	char text[256];	GetCharHP(text);	DrawPicture(gMapScreenUI, &dstRect, &dstRect);	TXNDrawCFStringTextBox(__CFStringMakeConstantString(text), &dstRect, gstyle, &goptions);}void DrawMapAll (void){	if(GameBuffer() != NULL)		SetGWorld(GameBuffer());	DrawMapUI();	DrawMap();	DrawMapCharacter();	DrawMapOverlay();	DrawMapUIOverlay();	DrawMapName();	DrawMapCharName();	DrawMapCharLv();	DrawMapCharHP();	if(GameBuffer() != NULL)	{		SetPortWindowPort(GameWindow());		DrawPicture(GameBuffer());	}}void DrawMapActive (void){	if(GameBuffer() != NULL)		SetGWorld(GameBuffer());	DrawMap();	DrawMapCharacter();	DrawMapOverlay();	DrawMapUIOverlay();	DrawMapCharHP();	if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)		QDFlushPortBuffer(GetWindowPort(GameWindow()), NULL);	else	{		SetPortWindowPort(GameWindow());		DrawPicture(GameBuffer());	}}void DrawMapMove (short direction){	long ticks = TickCount() + kMapWalkSpeed;	Point mapPosition = GetCharMapPosition();	if(MapCanMove(mapPosition.h / 32, mapPosition.v / 32, direction) == false)		return;	short perc = 100;	switch(direction)	{		case leftKey:			while(ticks > TickCount() && perc > 25)			{				perc = (ticks - TickCount()) * 100 / kMapWalkSpeed;				if(perc > 75)				{					SetCharMapPosition(mapPosition.h - 8, mapPosition.v);					SetCharMapFacing(kMapFacingWest1);					DrawMapActive();				}				else if(perc > 50)				{					SetCharMapPosition(mapPosition.h - 16, mapPosition.v);					SetCharMapFacing(kMapFacingWest2);					DrawMapActive();				}				else if(perc > 25)				{					SetCharMapPosition(mapPosition.h - 24, mapPosition.v);					SetCharMapFacing(kMapFacingWest2);					DrawMapActive();				}			}			SetCharMapPosition(mapPosition.h - 32, mapPosition.v);			SetCharMapFacing(kMapFacingWest1);			DrawMapActive();			break;		case rightKey:			while(ticks > TickCount() && perc > 25)			{				perc = (ticks - TickCount()) * 100 / kMapWalkSpeed;				if(perc > 75)				{					SetCharMapPosition(mapPosition.h + 8, mapPosition.v);					SetCharMapFacing(kMapFacingEast1);					DrawMapActive();				}				else if(perc > 50)				{					SetCharMapPosition(mapPosition.h + 16, mapPosition.v);					SetCharMapFacing(kMapFacingEast2);					DrawMapActive();				}				else if(perc > 25)				{					SetCharMapPosition(mapPosition.h + 24, mapPosition.v);					SetCharMapFacing(kMapFacingEast2);					DrawMapActive();				}			}			SetCharMapPosition(mapPosition.h + 32, mapPosition.v);			SetCharMapFacing(kMapFacingEast1);			DrawMapActive();			break;		case downKey:			while(ticks > TickCount() && perc > 25)			{				perc = (ticks - TickCount()) * 100 / kMapWalkSpeed;				if(perc > 75)				{					SetCharMapPosition(mapPosition.h, mapPosition.v + 8);					SetCharMapFacing(kMapFacingSouth1);					DrawMapActive();				}				else if(perc > 50)				{					SetCharMapPosition(mapPosition.h, mapPosition.v + 16);					SetCharMapFacing(kMapFacingSouth2);					DrawMapActive();				}				else if(perc > 25)				{					SetCharMapPosition(mapPosition.h, mapPosition.v + 24);					SetCharMapFacing(kMapFacingSouth2);					DrawMapActive();				}			}			SetCharMapPosition(mapPosition.h, mapPosition.v + 32);			SetCharMapFacing(kMapFacingSouth1);			DrawMapActive();			break;		case upKey:			while(ticks > TickCount() && perc > 25)			{				perc = (ticks - TickCount()) * 100 / kMapWalkSpeed;				if(perc > 75)				{					SetCharMapPosition(mapPosition.h, mapPosition.v - 8);					SetCharMapFacing(kMapFacingNorth1);					DrawMapActive();				}				else if(perc > 50)				{					SetCharMapPosition(mapPosition.h, mapPosition.v - 16);					SetCharMapFacing(kMapFacingNorth2);					DrawMapActive();				}				else if(perc > 25)				{					SetCharMapPosition(mapPosition.h, mapPosition.v - 24);					SetCharMapFacing(kMapFacingNorth2);					DrawMapActive();				}			}			SetCharMapPosition(mapPosition.h, mapPosition.v - 32);			SetCharMapFacing(kMapFacingNorth1);			DrawMapActive();			break;	}	HealStep();	RandomBattle();		while(TickCount() < ticks)		MoviesTask(NULL, DoTheRightThing);}void DrawBattleBackground (const Rect * dstRect){	if(GameBuffer() != NULL)		SetGWorld(GameBuffer());	else		SetPortWindowPort(GameWindow());	error = DrawPicture(gMapCurrBattlePict, dstRect, dstRect);	ErrorCheck(error, "\pDragonAlpha:DrawBattleBackground:DrawPicture");}void DrawBattleBackground (void){	if(GameBuffer() != NULL)		SetGWorld(GameBuffer());	else		SetPortWindowPort(GameWindow());	error = DrawPicture(gMapCurrBattlePict);	ErrorCheck(error, "\pDragonAlpha:DrawBattleBackground:DrawPicture");}void DrawBattleBackgroundFade (const Rect * dstRect){	float tickTime = 60.0;	long ticks = TickCount();	if(GameBuffer() != NULL)		SetGWorld(GameBuffer());	else		SetPortWindowPort(GameWindow());	while(ticks + tickTime > TickCount())	{		DrawTransparentPicture(gMapCurrBattlePict, dstRect, dstRect, (TickCount() - ticks) / tickTime);		if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)			QDFlushPortBuffer(GetWindowPort(GameWindow()), NULL);		else		{			SetPortWindowPort(GameWindow());			DrawPicture(GameBuffer());			SetGWorld(GameBuffer());		}		FlushEvents(everyEvent, 0);		MoviesTask(NULL, 6);		Delay(6, 0);	}	DrawBattleBackground(dstRect);	if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)		QDFlushPortBuffer(GetWindowPort(GameWindow()), NULL);	else	{		SetPortWindowPort(GameWindow());		DrawPicture(GameBuffer());		SetGWorld(GameBuffer());	}}void DrawTransparentBackground (const Rect * dstRect, float perc){	if(GameBuffer() != NULL)		SetGWorld(GameBuffer());	else		SetPortWindowPort(GameWindow());	error = DrawTransparentPicture(gMapCurrBattlePict, dstRect, dstRect, perc);	ErrorCheck(error, "\pDragonAlpha:DrawTransparentBackground:DrawPicture");}//*************************************************************************************//  internal functions//*************************************************************************************pascal OSStatus MapMenuEventHandler (EventHandlerCallRef myHandler, EventRef event, void * userData){	OSStatus	result		= eventNotHandledErr;	HICommand	command;	error = GetEventParameter(event, kEventParamDirectObject, typeHICommand, NULL, sizeof(HICommand), NULL, &command);	ErrorCheck(error, "\pDragonAlpha:DragonAlphaMainEventHandler:GetEventParameter");	switch(command.commandID)	{		case kDASaveGameCommand:			MapSaveGame();			result = noErr;			break;		case kDASaveGameAsCommand:			MapSaveGameAs();			result = noErr;			break;		case kDAQuitCommand:			QuitGame();			result = noErr;			break;	}	return result;}pascal OSStatus MapAppEventHandler (EventHandlerCallRef myHandler, EventRef event, void * userData){	OSStatus	result		= eventNotHandledErr;	UInt32		eventKind	= GetEventKind(event);	switch(eventKind)	{		case kEventAppActivated:			CGrafPtr oldPort;			error = GetGWorld(&oldPort);			SetPortWindowPort((WindowRef)userData);			DrawMapAll();			error = SetGWorld(oldPort);			break;	}	return result;}pascal OSStatus MapKeyEventHandler (EventHandlerCallRef myHandler, EventRef event, void * userData){	OSStatus	result		= eventNotHandledErr;	UInt32		eventKind	= GetEventKind(event);	if(FrontWindow() != (WindowRef)userData)		return result;	CGrafPtr oldPort;	error = GetGWorld(&oldPort);	SetPortWindowPort((WindowRef)userData);	switch(eventKind)	{		case kEventRawKeyDown:		case kEventRawKeyRepeat:			MapKeyAction(GetKeys());			break;	}	error = SetGWorld(oldPort);	return result;}pascal OSStatus MapMouseEventHandler (EventHandlerCallRef myHandler, EventRef event, void * userData){	OSStatus	result		= eventNotHandledErr;	UInt32		eventKind	= GetEventKind(event);	if(FrontWindow() != (WindowRef)userData)		return result;	CGrafPtr oldPort;	error = GetGWorld(&oldPort);	SetPortWindowPort((WindowRef)userData);	Point mouse;	GetMouse(&mouse);	switch(eventKind)	{		case kEventMouseDown:			if(mouse.h >= 8 && mouse.h <= 156 && mouse.v >= 0)			{				if(mouse.v >= 226 && mouse.v <= 256)				{					DrawSelectButton(11, 230, true);					PlayClickSound();					OpenGame();					result = noErr;				}				else if(mouse.v >= 267 && mouse.v <= 297)				{					DrawSelectButton(11, 271, true);					PlayClickSound();					MapSaveGame();					result = noErr;				}				else if(mouse.v >= 325 && mouse.v <= 355)				{					DrawSelectButton(11, 329, true);					PlayClickSound();					Equipment();					DrawMapAll();					if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)						QDFlushPortBuffer(GetWindowPort(GameWindow()), NULL);					result = noErr;				}				else if(mouse.v >= 366 && mouse.v <= 396)				{					DrawSelectButton(11, 370, true);					PlayClickSound();					MagicWindow(false);					DrawMapAll();					if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)						QDFlushPortBuffer(GetWindowPort(GameWindow()), NULL);					result = noErr;				}				else if(mouse.v >= 407 && mouse.v <= 437)				{					DrawSelectButton(11, 411, true);					PlayClickSound();					TechWindow(false);					DrawMapAll();					if(QDIsPortBuffered(GetWindowPort(GameWindow())) == true)						QDFlushPortBuffer(GetWindowPort(GameWindow()), NULL);					result = noErr;				}				else if(mouse.v >= 506 && mouse.v <= 536)				{					DrawSelectButton(11, 510, true);					PlayClickSound();					MapHelp();					result = noErr;				}				else if(mouse.v >= 564 && mouse.v <= 594)				{					DrawSelectButton(11, 568, true);					PlayClickSound();					QuitGame();					result = noErr;				}				else					MapMouseAction(&mouse);			}			else if(mouse.v >= 0)				MapMouseAction(&mouse);			break;		case kEventMouseDragged:			if(mouse.v >= 0)				MapMouseAction(&mouse);			break;		case kEventMouseMoved:			if(mouse.h >= 8 && mouse.h <= 156)			{				if(mouse.v >= 226 && mouse.v <= 256)					DrawSelectButton(11, 230, true);				else if(mouse.v >= 267 && mouse.v <= 297)					DrawSelectButton(11, 271, true);				else if(mouse.v >= 325 && mouse.v <= 355)					DrawSelectButton(11, 329, true);				else if(mouse.v >= 366 && mouse.v <= 396)					DrawSelectButton(11, 370, true);				else if(mouse.v >= 407 && mouse.v <= 437)					DrawSelectButton(11, 411, true);				else if(mouse.v >= 506 && mouse.v <= 536)					DrawSelectButton(11, 510, true);				else if(mouse.v >= 564 && mouse.v <= 594)					DrawSelectButton(11, 568, true);				else				{					DrawSelectButton(11, 230, false);					DrawSelectButton(11, 271, false);					DrawSelectButton(11, 329, false);					DrawSelectButton(11, 370, false);					DrawSelectButton(11, 411, false);					DrawSelectButton(11, 510, false);					DrawSelectButton(11, 568, false);				}			}			else			{				DrawSelectButton(11, 230, false);				DrawSelectButton(11, 271, false);				DrawSelectButton(11, 329, false);				DrawSelectButton(11, 370, false);				DrawSelectButton(11, 411, false);				DrawSelectButton(11, 510, false);				DrawSelectButton(11, 568, false);			}			break;	}	error = SetGWorld(oldPort);	return result;}pascal OSStatus MapWindowEventHandler (EventHandlerCallRef myHandler, EventRef event, void * userData){	OSStatus	result		= eventNotHandledErr;	UInt32		eventKind	= GetEventKind(event);	switch(eventKind)	{		case kEventWindowDrawContent:			SetPortWindowPort(GameWindow());			DrawMapAll();			break;	}	return result;}